class MaxHeap:
    def __init__(self):
        self.heap = []

    def _parent(self, index):
        return (index - 1) // 2

    def _left_child(self, index):
        return 2 * index + 1

    def _right_child(self, index):
        return 2 * index + 2

    def _swap(self, i, j):
        self.heap[i], self.heap[j] = self.heap[j], self.heap[i]

    def _heapify_up(self, index):
        while index > 0 and self.heap[self._parent(index)] < self.heap[index]:
            parent_index = self._parent(index)
            self._swap(index, parent_index)
            index = parent_index

    def _heapify_down(self, index):
        last_index = len(self.heap) - 1
        left_child_index = self._left_child(index)
        right_child_index = self._right_child(index)
        largest = index

        if left_child_index <= last_index and self.heap[left_child_index] > self.heap[largest]:
            largest = left_child_index

        if right_child_index <= last_index and self.heap[right_child_index] > self.heap[largest]:
            largest = right_child_index

        if largest != index:
            self._swap(index, largest)
            self._heapify_down(largest)

    def insert(self, item):
        self.heap.append(item)
        self._heapify_up(len(self.heap) - 1)

    def extract_max(self):
        if self.is_empty():
            raise IndexError("Heap is empty, cannot extract max.")
        if len(self.heap) == 1:
            return self.heap.pop()

        root = self.heap[0]
        self.heap[0] = self.heap.pop()
        self._heapify_down(0)
        return root

    def peek(self):
        if self.is_empty():
            raise IndexError("Heap is empty, no max element to peek.")
        return self.heap[0]

    def is_empty(self):
        return len(self.heap) == 0

    def size(self):
        return len(self.heap)

    def __len__(self):
        return self.size()

    def __str__(self):
        return str(self.heap)
